// ========================================
// NODE 2: NORMALIZE INPUT
// ========================================

const rawInput = $input.first().json;
const body = rawInput.body || rawInput;

function containsArabic(text) {
  return /[\u0600-\u06FF\u0750-\u077F\u08A0-\u08FF]/.test(text);
}

function normalizeArabic(text) {
  return text
    .replace(/[\u064B-\u065F\u0670]/g, '')
    .replace(/[\u0622\u0623\u0625]/g, '\u0627')
    .replace(/[\u0649]/g, '\u064A')
    .replace(/[\u0629]/g, '\u0647');
}

const userMessage = (body.user_message || body.message || '').trim();
const sessionId = body.session_id || 'session_' + Date.now();
const channel = ['chat', 'voice', 'whatsapp'].includes(body.channel) ? body.channel : 'chat';
const phone = body.phone || null;
const metadata = body.metadata || {};

let language = body.language;
if (!language || !['ar', 'en'].includes(language)) {
  language = containsArabic(userMessage) ? 'ar' : 'en';
}

const normalizedMessage = language === 'ar' ? normalizeArabic(userMessage) : userMessage.toLowerCase();

return {
  json: {
    user_message: userMessage,
    normalized_message: normalizedMessage,
    session_id: sessionId,
    channel: channel,
    language: language,
    phone: phone,
    metadata: metadata,
    timestamp: new Date().toISOString()
  }
};

// ========================================
// NODE 3: DETECT INTENT
// ========================================

const input = $input.first().json;
const msg = input.user_message;
const lang = input.language;

const intents = [
  {
    intent: 'COMPLAINT', agent: 'complaint', priority: 1,
    ar: ['شكوى', 'مشكلة', 'زعلان', 'مش راضي', 'سيء', 'وحش', 'عايز فلوسي', 'استرجاع', 'غلط', 'كذب', 'نصب'],
    en: ['complaint', 'problem', 'angry', 'not satisfied', 'bad', 'terrible', 'refund', 'return', 'wrong', 'lied', 'scam']
  },
  {
    intent: 'HUMAN_REQUEST', agent: 'escalation', priority: 2,
    ar: ['عايز اتكلم مع حد', 'موظف', 'خدمة عملاء', 'بني آدم', 'مدير', 'مسؤول'],
    en: ['talk to someone', 'human', 'customer service', 'real person', 'manager', 'supervisor']
  },
  {
    intent: 'LEGAL_THREAT', agent: 'escalation', priority: 0,
    ar: ['محامي', 'قانون', 'شرطة', 'نيابة', 'هنشر', 'فيسبوك', 'سوشيال'],
    en: ['lawyer', 'legal', 'police', 'court', 'post', 'facebook', 'social media']
  },
  {
    intent: 'WARRANTY', agent: 'warranty', priority: 3,
    ar: ['ضمان', 'تفعيل الضمان', 'شهادة ضمان', 'تصليح', 'صيانة', 'عيب صناعة'],
    en: ['warranty', 'guarantee', 'repair', 'maintenance', 'defect']
  },
  {
    intent: 'SALES_PRICE', agent: 'sales', priority: 4,
    ar: ['سعر', 'بكام', 'كام', 'تكلفة', 'عروض', 'خصم', 'تقسيط', 'اسعار'],
    en: ['price', 'cost', 'how much', 'offers', 'discount', 'installment']
  },
  {
    intent: 'SALES_RECOMMENDATION', agent: 'sales', priority: 5,
    ar: ['عايز اشتري', 'عايز مرتبة', 'انصحني', 'افضل', 'اختار', 'مقاسات', 'انواع', 'منتجات'],
    en: ['buy', 'purchase', 'recommend', 'suggest', 'best', 'sizes', 'types', 'mattress']
  },
  {
    intent: 'DELIVERY', agent: 'support', priority: 6,
    ar: ['توصيل', 'شحن', 'يوصل امتى', 'مدة التوصيل'],
    en: ['delivery', 'shipping', 'when arrive', 'delivery time']
  },
  {
    intent: 'STORE_INFO', agent: 'support', priority: 7,
    ar: ['فين الفرع', 'عنوان', 'مواعيد', 'رقم التليفون', 'فروع'],
    en: ['store', 'address', 'hours', 'phone', 'branches']
  }
];

let detected = { intent: 'GENERAL_SUPPORT', agent: 'support', confidence: 0.5, matched: [], priority: 99 };

for (const def of intents) {
  const keywords = lang === 'ar' ? def.ar : def.en;
  const matches = keywords.filter(k => msg.includes(k));
  if (matches.length > 0 && def.priority < detected.priority) {
    detected = {
      intent: def.intent,
      agent: def.agent,
      confidence: Math.min(0.95, 0.5 + (matches.length * 0.15)),
      matched: matches,
      priority: def.priority
    };
  }
}

return {
  json: {
    ...input,
    intent: detected.intent,
    target_agent: detected.agent,
    confidence: detected.confidence,
    matched_keywords: detected.matched
  }
};

// ========================================
// SALES AGENT
// ========================================

const input = $input.first().json;
const lang = input.language;

const products = [
  { id: 'prod_001', name_ar: 'مرتبة يانسن أورثوبيديك', name_en: 'Janssen Orthopedic', price: 12500, warranty: 10 },
  { id: 'prod_002', name_ar: 'مرتبة يانسن ميموري فوم', name_en: 'Janssen Memory Foam', price: 15000, warranty: 12 },
  { id: 'prod_003', name_ar: 'مرتبة يانسن سوبر سوفت', name_en: 'Janssen Super Soft', price: 10000, warranty: 8 }
];

let responseText = '';
let responseType = 'text';
let productCard = null;

if (input.intent === 'SALES_PRICE') {
  responseText = lang === 'ar'
    ? `تمام! أسعار المراتب عندنا بتبدأ من ${products[2].price.toLocaleString()} جنيه.\n\nعندنا موديلات مختلفة:\n• ${products[0].name_ar}: ${products[0].price.toLocaleString()} جنيه (ضمان ${products[0].warranty} سنين)\n• ${products[1].name_ar}: ${products[1].price.toLocaleString()} جنيه (ضمان ${products[1].warranty} سنة)\n• ${products[2].name_ar}: ${products[2].price.toLocaleString()} جنيه (ضمان ${products[2].warranty} سنين)\n\nعايز تعرف تفاصيل أكتر عن موديل معين؟`
    : `Great! Our mattress prices start from ${products[2].price.toLocaleString()} EGP.\n\nWe have different models:\n• ${products[0].name_en}: ${products[0].price.toLocaleString()} EGP (${products[0].warranty}-year warranty)\n• ${products[1].name_en}: ${products[1].price.toLocaleString()} EGP (${products[1].warranty}-year warranty)\n• ${products[2].name_en}: ${products[2].price.toLocaleString()} EGP (${products[2].warranty}-year warranty)\n\nWould you like more details about a specific model?`;
} else {
  responseText = lang === 'ar'
    ? 'أهلاً! أنا هنا أساعدك تختار المرتبة المناسبة ليك. عايز تعرف عن الأسعار ولا عايز نصيحة؟'
    : "Hello! I'm here to help you choose the right mattress. Would you like to know about prices or get a recommendation?";
  responseType = 'product_card';
  productCard = {
    id: products[0].id,
    name: lang === 'ar' ? products[0].name_ar : products[0].name_en,
    description: lang === 'ar' ? 'مرتبة طبية عالية الجودة' : 'Premium orthopedic mattress',
    price: `${products[0].price.toLocaleString()} EGP`,
    warranty: `${products[0].warranty} ${lang === 'ar' ? 'سنين' : 'years'}`
  };
}

return {
  json: {
    ...input,
    response_text: responseText,
    response_type: responseType,
    product_card: productCard,
    escalated: false,
    next_action: 'await_response'
  }
};

// ========================================
// SUPPORT AGENT
// ========================================

const input = $input.first().json;
const lang = input.language;

let responseText = '';

if (input.intent === 'DELIVERY') {
  responseText = lang === 'ar'
    ? 'بخصوص التوصيل:

• القاهرة والجيزة: 2-3 أيام عمل
• الإسكندرية: 3-5 أيام عمل
• باقي المحافظات: 5-7 أيام عمل

التوصيل مجاني للطلبات فوق 5000 جنيه.

إنت فين بالظبط علشان أقولك المدة المتوقعة؟'
    : 'Regarding delivery:

• Cairo & Giza: 2-3 business days
• Alexandria: 3-5 business days
• Other governorates: 5-7 business days

Free delivery for orders above 5000 EGP.

Where are you located?';
} else if (input.intent === 'STORE_INFO') {
  responseText = lang === 'ar'
    ? 'عندنا فروع في:

• فرع مدينة نصر: شارع عباس العقاد
• فرع المهندسين: شارع جامعة الدول العربية

مواعيد العمل: من 9 صباحاً لـ 9 مساءً

عايز عنوان فرع معين؟'
    : 'We have branches in:

• Nasr City: Abbas El-Akkad St.
• Mohandessin: Arab League St.

Working hours: 9 AM to 9 PM

Would you like a specific branch address?';
} else {
  responseText = lang === 'ar'
    ? 'أهلاً! أنا هنا أساعدك. ممكن أفيدك في:
• معلومات عن التوصيل
• فروعنا ومواعيد العمل
• أي استفسار عام

اتفضل اسألني!'
    : "Hello! I'm here to help. I can assist you with:
• Delivery information
• Branch locations
• General inquiries

Please ask!";
}

return {
  json: {
    ...input,
    response_text: responseText,
    response_type: 'text',
    escalated: false,
    next_action: 'await_response'
  }
};

// ========================================
// WARRANTY AGENT
// ========================================

const input = $input.first().json;
const lang = input.language;
const msg = input.user_message;

let responseText = '';
let escalated = false;
let nextAction = 'await_response';
let escalationQueue = null;
let escalationPriority = null;

const claimKeywords = lang === 'ar' ? ['طلب', 'استبدال', 'تصليح'] : ['claim', 'replace', 'repair'];
const needsClaim = claimKeywords.some(k => msg.includes(k));

if (needsClaim) {
  responseText = lang === 'ar'
    ? 'تمام، هساعدك في موضوع الضمان. علشان نقدر نفتحلك طلب، هحتاج منك:\n\n1. رقم الفاتورة\n2. تاريخ الشراء\n3. وصف المشكلة\n\nلو معاك البيانات دي، هحولك لقسم الضمان.'
    : "Sure, I'll help you with the warranty. To file a claim, I'll need:\n\n1. Invoice number\n2. Purchase date\n3. Description of the issue\n\nI'll connect you with our warranty department.";
  escalated = true;
  nextAction = 'transfer_to_human';
  escalationQueue = 'warranty_queue';
  escalationPriority = 'high';
} else {
  responseText = lang === 'ar'
    ? 'ضمان يانسن 10 سنين وبيغطي:\n\n✅ عيوب الصناعة\n✅ تهالك السوست\n✅ انخفاض المرتبة أكتر من 3 سم\n\n❌ الضمان مش بيشمل: سوء الاستخدام، البقع، الحرق\n\nمحتاج مساعدة في تفعيل الضمان ولا عندك مشكلة في المنتج؟'
    : 'Janssen warranty is 10 years and covers:\n\n✅ Manufacturing defects\n✅ Spring deterioration\n✅ Sagging more than 3cm\n\n❌ Excludes: Misuse, stains, burns\n\nDo you need help activating warranty or have an issue?';
}

return {
  json: {
    ...input,
    response_text: responseText,
    response_type: escalated ? 'handover' : 'text',
    escalated: escalated,
    next_action: nextAction,
    escalation_queue: escalationQueue,
    escalation_priority: escalationPriority
  }
};

// ========================================
// COMPLAINT AGENT
// ========================================

const input = $input.first().json;
const lang = input.language;

const responseText = lang === 'ar'
  ? 'معلش جداً على اللي حصل. فاهم زعلك تماماً.\n\nعلشان أقدر أساعدك، ممكن تقولي:\n1. إيه اللي حصل بالظبط؟\n2. امتى ده حصل؟\n3. رقم الفاتورة لو معاك؟\n\nكل المعلومات دي هتساعدني أحل الموضوع معاك.'
  : "I'm truly sorry about what happened. I completely understand your frustration.\n\nTo help you, could you tell me:\n1. What exactly happened?\n2. When did this occur?\n3. Your invoice number if available?\n\nThis will help me resolve this for you.";

return {
  json: {
    ...input,
    response_text: responseText,
    response_type: 'text',
    escalated: true,
    next_action: 'transfer_to_human',
    escalation_queue: 'complaints_queue',
    escalation_priority: 'high'
  }
};

// ========================================
// ESCALATION AGENT
// ========================================

const input = $input.first().json;
const lang = input.language;

let priority = 'normal';
let queue = 'support_queue';

if (input.intent === 'LEGAL_THREAT') {
  priority = 'critical';
  queue = 'priority_queue';
}

const responseText = lang === 'ar'
  ? 'هحولك دلوقتي لأحد موظفين خدمة العملاء اللي هيقدر يساعدك أكتر. استنى لحظة من فضلك.'
  : "I'm connecting you now to one of our customer service representatives. Please hold.";

return {
  json: {
    ...input,
    response_text: responseText,
    response_type: 'handover',
    escalated: true,
    next_action: 'transfer_to_human',
    escalation_queue: queue,
    escalation_priority: priority
  }
};

// ========================================
// NODE 7: FORMAT OUTPUT
// ========================================

const input = $input.first().json;

let responseText = input.response_text || '';

// Channel-specific formatting
if (input.channel === 'voice') {
  responseText = responseText.replace(/[\u{1F300}-\u{1F9FF}]/gu, '').replace(/\n+/g, '. ');
  if (responseText.length > 200) responseText = responseText.substring(0, 197) + '...';
} else if (input.channel === 'chat') {
  responseText = responseText.replace(/\n/g, '<br>');
}

const response = {
  response_type: input.response_type || 'text',
  content: { text: responseText },
  next_action: input.next_action || 'await_response',
  agent_used: input.target_agent,
  intent: input.intent,
  confidence_score: input.confidence,
  session_id: input.session_id,
  language: input.language,
  channel: input.channel,
  matched_keywords: input.matched_keywords
};

if (input.product_card) {
  response.content.product = input.product_card;
}

if (input.escalated) {
  response.escalation = {
    queue: input.escalation_queue,
    priority: input.escalation_priority,
    reason: input.intent === 'LEGAL_THREAT' ? 'legal_threat' : 'agent_request'
  };
}

return { json: response };

// ========================================
// NODE 8: LOG & RETURN
// ========================================

const response = $input.first().json;

console.log('[JANSSEN_AI_LOG]', JSON.stringify({
  session_id: response.session_id,
  agent: response.agent_used,
  intent: response.intent,
  confidence: response.confidence_score,
  escalated: !!response.escalation,
  timestamp: new Date().toISOString()
}));

return { json: response };
